"""
MKT Christ Commentary — Proverbs chapters 13–15
Run: python3 scripts/zc-christ-proverbs-13-15.py

Source data used:
- data/interlinear/proverbs.json
- data/translation/draft/mediating/proverbs.json (MKT text)
- data/commentary/mkt-christ/proverbs.json (existing chs 1–9)

Key decisions:
- Classification levels used throughout: direct (explicit NT citation), allusion
  (NT verbal echo of this verse), type (OT figure fulfilled in Christ), theme
  (theological principle finding fullest expression in Christ), revelation of God
  (what this says about God, embodied in the incarnate Son).
- 13:7 (acts rich/poor) is classified 'allusion' — 2 Cor 8:9 is a near-citation.
- 13:8 (ransom) is classified 'type' — the wealth-ransom image is fulfilled in
  Christ's self-giving as a ransom (Mark 10:45).
- 14:5 (faithful witness) is classified 'type' — Christ as the faithful witness
  (Rev 3:14; 19:11).
- 14:9 (atonement) connects directly to Christ's high-priestly work.
- 14:12 (path that seems right → death) is classified 'direct' via John 14:6
  where Christ claims to be THE Way.
- 14:19 (wicked bow before good) is classified 'theme' toward Phil 2:10–11.
- 14:32 (hope even in death) is classified 'type' — the righteous person's hope
  in death is fulfilled in resurrection through Christ.
- 15:8 (sacrifice of wicked detested; prayer of upright = delight) is classified
  'type' — the distinction between acceptable and unacceptable sacrifice is resolved
  in Christ's once-for-all offering (Heb 10:4–10).
- 15:24 (way of life leads upward) is classified 'theme' — Christ's ascension as
  the archetypal "way up" out of Sheol.
- 15:33 (humility before honor) is classified 'direct' via Phil 2:8–9.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "13": {
    "1": '<p><em>Type.</em> The wise son who heeds his father\'s instruction embodies the covenantal pattern that Jesus fulfills as the perfectly obedient Son. Where Israel as son repeatedly rejected the Father\'s instruction (Hos 11:1–2), and where individual Israelite sons failed to heed wisdom\'s call, Jesus as the Son whose food was "to do the will of him who sent me" (John 4:34) constitutes the obedient son in whom the father\'s instruction is finally and fully received. The sonship-through-obedience pattern in Proverbs aims at what becomes literal in the incarnation.</p>',
    "2": '<p><em>Theme.</em> "A man eats well from the fruit of his words" — the life-sustaining power of right speech finds its fullest expression in Christ, whose words are spirit and life (John 6:63). He declares, "The words I have spoken to you — they are full of the Spirit and life" (John 6:63). The contrast between life-giving words and craving violence maps onto the opposition between Christ\'s speech (which feeds) and the adversary\'s (which destroys). Christ\'s teaching is the food from which the wise person eats well.</p>',
    "3": '<p><em>Revelation of God.</em> The one who guards his mouth guards his life — a principle perfectly embodied in Christ, who "committed no sin, and no deceit was found in his mouth" (1 Pet 2:22, citing Isa 53:9). Christ\'s perfect speech-discipline is not mere self-control but the overflow of a heart perfectly aligned with the Father. He is the living demonstration that guarding the mouth — filling it only with truth, grace, and what edifies — is the form of life itself.</p>',
    "4": '<p><em>Theme.</em> The diligent soul is richly satisfied — a principle Christ both embodies and fulfills eschatologically. He is himself the satisfaction of the soul\'s craving: "Whoever comes to me will never be hungry, and whoever believes in me will never be thirsty" (John 6:35). The lazy soul that craves and receives nothing corresponds to the person who wants the benefits of wisdom without the discipline of formation; the diligent soul who is richly satisfied corresponds to those who "hunger and thirst for righteousness" and are promised they "will be filled" (Matt 5:6).</p>',
    "5": '<p><em>Revelation of God.</em> The righteous man\'s hatred of falsehood reflects the character of the God who "cannot lie" (Titus 1:2) and who is himself Truth (John 14:6). Christ, who identifies himself as "the truth," embodies this hatred of falsehood at the deepest ontological level: he is not merely a reliable witness but the ground of all truthfulness. His condemnation of those who "love falsehood" (Rev 22:15) and his promise that "the truth will set you free" (John 8:32) reveal the Father\'s own character expressed in the Son.</p>',
    "6": '<p><em>Theme.</em> Righteousness guards the one who walks uprightly — a protection that, in Paul\'s account, comes through imputation rather than self-achievement. Christ "is made our righteousness" (1 Cor 1:30): the guarding function of righteousness is now located in the One in whom we stand rather than in our own moral performance. The wicked brought down by wickedness corresponds to the old humanity; the upright guarded by righteousness corresponds to those who stand in the Righteous One.</p>',
    "7": '<p><em>Allusion.</em> "One person acts rich and has nothing; another acts poor yet has great wealth" — Paul draws directly on this paradox in 2 Cor 8:9: "Though he was rich, yet for your sake he became poor, so that you through his poverty might become rich." Christ is the supreme instance of the second figure — he who has all things (John 17:5, 24) entered poverty (Luke 9:58; Phil 2:6–8) so that those with nothing might inherit everything. The proverb\'s apparent reversal of economic logic is realized literally in the incarnation.</p>',
    "8": '<p><em>Type.</em> "A man\'s wealth may ransom his life" (<em>kōper</em>, a redemption price) introduces the economic theology of ransom that culminates in Christ. Jesus identifies himself as the one who came "to give his life as a ransom for many" (<em>lytron anti pollōn</em>, Mark 10:45), applying the <em>kōper</em> institution to himself as the payment that releases the bound. The wealthy man\'s ransom of his physical life in v. 8 is a provisional instance of what Christ accomplishes eschatologically: the redemption of life from its debt to death.</p>',
    "9": '<p><em>Theme.</em> "The light of the righteous shines with joy, but the lamp of the wicked will be extinguished" — Christ identifies himself as "the light of the world" (John 8:12; 9:5) and as the one who makes his followers "the light of the world" (Matt 5:14). The extinguishing of the wicked\'s lamp (a judgment image throughout Proverbs; cf. 20:20; 24:20) corresponds to the darkness into which those who reject the light are condemned (John 3:19). Christ is the Light that creates all other light, the true referent of the righteous person\'s joy-brightness.</p>',
    "10": '<p><em>Theme.</em> Pride produces nothing but conflict — the anthropological diagnosis that underlies the gospel\'s call to repentance. Christ himself is "gentle and lowly in heart" (Matt 11:29) and offers his yoke as the alternative to pride\'s conflict-generating burden. The wisdom found in those who take counsel (<em>nôʿāṣîm</em>) points toward the community of discernment that Christ establishes through the Spirit\'s counsel (John 16:13), where wisdom comes through mutual submission rather than pride-driven assertion.</p>',
    "11": '<p><em>Theme.</em> Wealth gathered gradually through labor grows — the principle of legitimate, patient accumulation extends into Christ\'s parables of the kingdom (Matt 25:14–30; Luke 19:12–27), where faithful stewardship over time produces multiplication. The shrinking of fraudulent wealth corresponds to the judgment of those who misuse what is entrusted to them. Christ as the returning master rewards those who have labored faithfully and withholds from those who have not — the same moral logic of gradual vs. fraudulent gain.</p>',
    "12": '<p><em>Type.</em> "Hope deferred makes the heart grow sick, but a longing fulfilled is a tree of life" — the tree of life (<em>ʿēṣ ḥayyîm</em>) reappears in Revelation 22:2 as the eschatological healing-tree in the new Jerusalem, available to all who have washed their robes. The entire arc of redemptive history is one of hope deferred — the exile, the waiting, the groaning (Rom 8:22–25) — and its fulfillment in Christ, who is himself the resolution of the long wait. His resurrection is the fulfilled longing that ends the sickness of deferred hope.</p>',
    "13": '<p><em>Revelation of God.</em> "Whoever respects the commandment will be rewarded" — Christ, who came not to abolish but to fulfill the law (Matt 5:17), is the supreme respecter of the commandment, keeping it perfectly in both letter and spirit. He bore the punishment for those who "despise instruction" (the cross as the consequence of covenant-breaking) precisely so that those who are in him might receive the reward. His resurrection is the reward promised to the one who respects the commandment to the uttermost.</p>',
    "14": '<p><em>Allusion.</em> "The teaching of the wise is a fountain of life, turning one away from the traps of death" — Jesus applies this directly to himself: "The water I give them will become in them a spring of water welling up to eternal life" (John 4:14). The wisdom tradition\'s fountain-of-life metaphor is absorbed into Christ\'s self-identification as the source of living water. His teaching is not merely a path away from death-traps but the actual supply of life that removes the need to pursue death-alternatives.</p>',
    "15": '<p><em>Theme.</em> "Good understanding wins favor" (<em>śekel ṭôb yitten-ḥēn</em>) — Luke 2:52 describes Jesus growing "in wisdom and stature, and in favor with God and man," the same combination of understanding and favor this verse describes. Christ is the one human being who achieved perfect understanding and therefore received perfect favor — divine (<em>ḥēn</em> from God) and social (<em>ḥēn</em> from people). His favor was not gained by manipulation but was the natural social consequence of genuine wisdom embodied.</p>',
    "16": '<p><em>Revelation of God.</em> "Every prudent person acts from knowledge" — Christ acts always from perfect knowledge of the Father\'s will and of human hearts (John 2:25; 16:30). His actions are never reactive, impulsive, or misinformed; they flow from the knowledge that is his as the eternal Son. This is the pattern to which wisdom formation aspires — acting from knowing — and which Christ embodies not as an ideal but as the actual structure of his life: he knows, and therefore acts rightly in every circumstance.</p>',
    "17": '<p><em>Type.</em> "A trustworthy envoy brings healing" — Christ is the divine envoy par excellence, sent from the Father (John 20:21; Heb 1:1–2) and described as both faithful (<em>pistos</em>, Rev 19:11) and healing (Matt 4:23; Luke 4:18). The messenger who brings healing is a type fulfilled in the one whose very name (<em>Yēšûaʿ</em>) means "salvation." Where a wicked messenger causes harm, Christ the Sent One brings the total restoration of <em>šālôm</em> — healing at every level of human brokenness.</p>',
    "18": '<p><em>Theme.</em> Honor comes to whoever accepts correction — the principle Christ embodies in his submission to the Father\'s discipline through suffering. Hebrews 12:5–11 grounds the entire theology of divine correction in this wisdom-tradition principle: God disciplines those he loves. Christ himself "learned obedience from what he suffered" (Heb 5:8), receiving through the discipline of the cross the highest honor: the name above every name (Phil 2:9). His acceptance of correction is the model for the disciple\'s formation.</p>',
    "19": '<p><em>Theme.</em> "A longing fulfilled is sweet to the soul" — Christ is the fulfillment of the deepest human longing (the <em>ʾaṭṭārâ</em>, the desire, that Proverbs describes as orienting the wise person toward wisdom). Paul describes Christ as "the one our ancestors wrote about" (John 5:46), the object toward whom all the promises pointed (2 Cor 1:20). The sweetness of longing-fulfilled is the experience of those who meet Jesus: the disciples on the Emmaus road whose "hearts burned within them" (Luke 24:32) are the embodiment of this verse.</p>',
    "20": '<p><em>Theme.</em> "Walk with the wise and you will become wise" — Christ as the supreme companion of formation. The disciples who walked with Jesus for three years became wise not by studying curricula but by proximity — the formative exposure that Proverbs identifies as the mechanism of wisdom-transmission. "Follow me" (Mark 1:17) is Christ\'s wisdom-invitation; discipleship is the sustained walking-with-the-Wise that this verse prescribes. The community gathered around Christ is the most powerful instance of wisdom-formation through proximity.</p>',
    "21": '<p><em>Theme.</em> "The righteous will be rewarded with good" — the eschatological promise that grounds all of wisdom\'s ethical instruction. Christ\'s resurrection is the first and paradigmatic instance of the righteous person receiving good as their reward: the one who lived perfectly righteously received life in its fullest form as the divine response to his faithfulness. For those in Christ, his resurrection is the guarantee that the reward promised to the righteous (<em>šillēm ṭôb</em>) will be received.</p>',
    "22": '<p><em>Theme.</em> "A good man leaves an inheritance for his grandchildren, but the wealth of a sinner is stored up for the righteous" — Christ as the testator of the new covenant leaves an inheritance to his children. Hebrews identifies believers as "heirs of what is promised" (Heb 6:17) through Christ who mediates the "new covenant, so that those who are called may receive the promised eternal inheritance" (Heb 9:15). The wealth stored up for the righteous is the kingdom prepared before the foundation of the world (Matt 25:34).</p>',
    "23": '<p><em>Revelation of God.</em> "The land of the poor may produce abundant food, but it is swept away through injustice" — the God who condemns injustice against the productive poor is the God embodied in Christ who denounces those who "devour widows\' houses" (Mark 12:40) and who himself becomes poor (2 Cor 8:9) to stand in solidarity with the economically marginalized. The prophetic tradition\'s concern for the poor-swept-by-injustice is fulfilled in Christ\'s identification with them (Matt 25:40) and his kingdom\'s promise to reverse their situation (Luke 6:20).</p>',
    "24": '<p><em>Allusion.</em> "Whoever loves him disciplines him while there is time" — Hebrews 12:6 cites the companion verse (Prov 3:12) directly: "The Lord disciplines the one he loves." The father\'s rod in Proverbs becomes the Father\'s discipline in Hebrews, applied through Christ who himself experienced the rod of affliction (Isa 53:5 — "the punishment that brought us peace was on him"). Both the discipline that forms (the child corrected by the loving father) and the discipline that redeems (the Son bearing the punishment) flow from love\'s determination to shape the beloved toward life.</p>',
    "25": '<p><em>Theme.</em> "The righteous eat until they are satisfied" — Christ both feeds and is himself the food that satisfies. The feeding miracles (Matt 14:13–21; 15:32–38) are enacted parables of this proverb: those who follow the righteous one do not go hungry. "I am the bread of life" (John 6:35) identifies Christ as the food that righteous eating anticipates. The hunger of the wicked corresponds to the emptiness that remains when the soul feeds on anything other than the one who is himself satisfaction.</p>'
  },
  "14": {
    "1": '<p><em>Type.</em> "A wise woman builds up her household" — Christ is the one who builds his household. "I will build my church" (Matt 16:18) applies house-building to the community of the redeemed; the Pauline image of the church as "God\'s building" with Christ as the foundation (1 Cor 3:9–11) and the household of God "built on the foundation of the apostles and prophets, with Christ Jesus himself as the chief cornerstone" (Eph 2:20–22) fulfills the wise-builder image. Folly that tears down its own house is the counterpart of apostasy that abandons the cornerstone.</p>',
    "2": '<p><em>Revelation of God.</em> "Whoever walks in uprightness fears the LORD" — Christ is the one human being who walked in perfect uprightness, whose fear of the LORD was not the trembling of guilt but the glad deference of the beloved Son to the Father. Isaiah describes the messianic figure as one on whom "the Spirit of the LORD" rests, including "the Spirit of the fear of the LORD" (Isa 11:2–3). Christ\'s uprightness and reverence for the Father is the lived reality that this proverb articulates as the proper pattern of human existence before God.</p>',
    "3": '<p><em>Theme.</em> "The lips of the wise protect them" — Christ\'s wise speech consistently protected not only himself but those around him from spiritual harm. His rebuke of Peter ("Get behind me, Satan!" Matt 16:23) and his silencing of demons (Mark 1:25) are acts of protective speech. In Gethsemane, when asked if he is Jesus of Nazareth, he identifies himself and the soldiers fall back (John 18:6) — his word exercises protective power. His speech as the Logos is the ultimate instance of words that "protect."</p>',
    "4": '<p><em>Theme.</em> "Where there are no oxen, the stall is clean, but much increase comes through the strength of an ox" — the productive mess of genuine work is the principle behind Christ\'s willingness to enter the contamination of human existence. The incarnation is the supreme version of the hard-work principle: the stall of creation became "dirty" (groaning, broken, death-filled) when God entered it in Christ, but "much increase" — resurrection life, reconciled creation, the harvest of the kingdom — comes only through this costly, strength-filled engagement. The clean but empty stall is the world without the incarnation.</p>',
    "5": '<p><em>Type.</em> "An honest witness does not lie" — Christ is the faithful and true witness, the final embodiment of truthful testimony. Revelation applies to him the title "the faithful and true witness" (<em>ho martys ho pistos kai alēthinos</em>, Rev 3:14; 19:11), echoing the language of faithful testimony that Proverbs consistently upholds. His testimony about himself ("I am the way, the truth, and the life," John 14:6) is the most far-reaching truth-claim any witness has ever made — and he authenticates it through resurrection.</p>',
    "6": '<p><em>Theme.</em> "Knowledge comes easily to a person of understanding" — Christ gives wisdom to those whose hearts are prepared to receive it, while those who approach him with hard hearts ("lest they see with their eyes, hear with their ears, and understand with their hearts and turn," Matt 13:15) remain in their blindness. His explanation: "To you it has been given to know the secrets of the kingdom of heaven, but to them it has not been given" (Matt 13:11) — not arbitrary withholding but the recognition that understanding is the condition for receiving further understanding.</p>',
    "7": '<p><em>Theme.</em> "Stay away from a foolish person — there is no knowledge on his lips" — Paul\'s warnings about "foolish controversies" (Titus 3:9), "the foolish and ignorant arguments" that produce quarrels (2 Tim 2:23), and his instruction to "have nothing to do with the fruitless deeds of darkness" (Eph 5:11) apply this proverb ecclesially. Christ himself practiced selective engagement: he answered the Pharisees\' trick questions only to expose their foolishness (Matt 22:15–46) and then stopped engaging them when it became clear no learning was intended.</p>',
    "8": '<p><em>Revelation of God.</em> "The wisdom of the prudent is to understand his way" — Christ is the Way who understands himself as Way (John 14:6). His perfect self-knowledge — "I know where I came from and where I am going" (John 8:14) — is the fullest possible expression of this proverb\'s principle. The prudent person\'s wisdom is to understand their particular path; Christ\'s wisdom is to BE the path that all paths are to understand. His self-understanding is not a model for imitation but the ontological ground that makes all human self-understanding possible.</p>',
    "9": '<p><em>Type.</em> "Fools scoff at making amends for sin, but among the upright there is goodwill" — the "making amends" (<em>ʾāšām</em>, guilt offering, reparation) points toward the sacrificial system that Christ fulfills. He is both the guilt-offering that makes amends and the upright one among whom goodwill dwells. Hebrews 10:4–10 contrasts the inadequate sacrifices of the old system (scoffed at by fools as insufficient anyway) with Christ\'s once-for-all offering that actually deals with sin. The "goodwill" (<em>rāṣôn</em>, pleasure, acceptance) among the upright is the divine favor that rests on the Son (Matt 3:17).</p>',
    "10": '<p><em>Revelation of God.</em> "Each heart knows its own sorrow, and no outsider can fully share its joy" — Christ enters the interiority that no human being can fully enter. He who is "familiar with suffering" (Isa 53:3) knows each heart\'s particular grief not as an outside observer but as the incarnate one who has taken up human sorrow as his own (Matt 8:17, citing Isa 53:4). The sorrow that no outsider can share is shared by the one who is not merely an outsider: "we do not have a high priest who is unable to empathize with our weaknesses" (Heb 4:15).</p>',
    "11": '<p><em>Theme.</em> "The household of the wicked will be ruined, but the tent of the upright will flourish" — the flourishing tent (<em>ʾōhel</em>) of the upright echoes Israel\'s tabernacle-dwelling, the tent of God\'s presence. Christ\'s body is the true temple/tent of God\'s dwelling: "The Word became flesh and dwelt (<em>eskēnōsen</em>, tabernacled) among us" (John 1:14). The flourishing of the upright\'s tent is the flourishing of the community that becomes God\'s dwelling place through the Spirit (Eph 2:22). The wicked\'s ruined house corresponds to the old house of stone temple that was torn down (Matt 24:2).</p>',
    "12": '<p><em>Direct.</em> "There is a path that seems right to a person, but it leads to death in the end" — Jesus responds to this verse directly: "I am the way, and the truth, and the life. No one comes to the Father except through me" (John 14:6). The many paths that seem right but lead to death are the alternative to the one true Way. His statement does not merely add Christ to the list of wise teachers — it claims that he alone is the referent of all true way-following, and that all other ways, however plausible, are the paths-toward-death that Proverbs identifies here.</p>',
    "13": '<p><em>Revelation of God.</em> "Even in laughter the heart may ache, and the end of joy can be sorrow" — Christ, who was "despised and rejected by men, a man of sorrows and acquainted with grief" (Isa 53:3), knew this depth of human experience. His weeping at Lazarus\'s tomb (John 11:35) in the face of the disciples\' professed faith, his "loud cries and tears" in Gethsemane (Heb 5:7), and his cry of dereliction (Mark 15:34) show the deep ache beneath the surface. He enters human grief fully, making the joy-that-ends-in-sorrow his own in order to transform it into sorrow-that-ends-in-joy (John 16:20).</p>',
    "14": '<p><em>Theme.</em> "One who turns away from faithfulness is filled with the results of his own choices" — the gospel\'s logic of bearing one\'s own consequences is applied in reverse to Christ: he who had no faithlessness to bear bore our results as if they were his own. "God made him who had no sin to be sin for us" (2 Cor 5:21) — he received the consequences of faithlessness without having been faithless. This exchange (he bearing what belongs to us; we receiving what belongs to him) is the heart of Paul\'s atonement theology, presupposed by this verse\'s consequence-logic.</p>',
    "15": '<p><em>Theme.</em> "The prudent person gives careful thought to his steps" — Christ exercises perfect discernment about timing, audience, and engagement. He does not heal publicly when secrecy is appropriate (Mark 1:44); he does not answer when silence is wiser (Mark 14:61); he does not go to Jerusalem ahead of time (John 7:6–8). The "careful thought to his steps" that Proverbs commends to the prudent is embodied in Christ\'s deliberate, unhurried navigation of his own earthly mission — he is never reactive, always knowing the step he is taking and why.</p>',
    "16": '<p><em>Revelation of God.</em> "A wise man fears and turns from evil" — Christ\'s perfect fear of God is the model of this verse. Isaiah 11:3 describes the messianic Spirit\'s gift as "the Spirit of the fear of the LORD"; the servant who "delights in the fear of the LORD" is the coming king who turns from evil with perfect consistency. In Gethsemane, Christ\'s "reverent submission" (<em>eulabeia</em>, Heb 5:7) — his God-fearing — coexisted with full acceptance of the Father\'s will. His fear was not terror but the deep reverential submission that is the disposition of perfect wisdom.</p>',
    "17": '<p><em>Theme.</em> "A quick-tempered person acts foolishly, and a person who schemes wickedly is despised" — Christ demonstrates the opposite of both: in the face of arrest, trial, and mockery he exhibits the "slow to anger" that Proverbs consistently attributes to wisdom (14:29; 16:32). James 1:19–20 grounds the practical prohibition on quick anger in the nature of "the righteousness of God" — the character of Christ who never schemed, reacted rashly, or allowed anger to drive his actions. His patience under provocation is the lived form of this proverb\'s positive counterpart.</p>',
    "18": '<p><em>Theme.</em> "The prudent are crowned with knowledge" — the crowning of the wise with knowledge is an eschatological image that points toward the crowns of the faithful (2 Tim 4:8; Rev 2:10; Jas 1:12). Christ first receives the crown of thorns as a mockery (Matt 27:29) and then the diadem of many crowns as the glorified Lord (Rev 19:12). His path — from the crown of shame to the crown of glory — is the paradigm of the wisdom-trajectory: the one who truly possesses knowledge is vindicated and crowned in the end.</p>',
    "19": '<p><em>Theme.</em> "Evil people will bow before those who are good, and the wicked at the gates of the righteous" — this is realized eschatologically in Philippians 2:10–11: "at the name of Jesus every knee should bow... and every tongue acknowledge that Jesus Christ is Lord." The proverb describes a reversal of present power arrangements; Paul applies it to the cosmic acknowledgment of Christ\'s lordship that is the final destiny of all creation — including those who opposed him. The "gates of the righteous" become the judgment seat before which all must appear.</p>',
    "20": '<p><em>Theme.</em> "Even his neighbor dislikes a poor person, but a rich person has many friends" — Christ becomes poor to identify with the disliked, friendless poor. In his earthly ministry he deliberately associates with the marginalized, tax collectors, sinners, and the socially isolated, reversing the social logic this proverb describes. The disciples who abandoned him at his arrest (Matt 26:56) confirm the proverb\'s observation even in his own experience. But Christ is also the "friend of sinners" (Matt 11:19) who befriends the poor precisely when no one else will.</p>',
    "21": '<p><em>Direct.</em> "Blessed is whoever shows kindness to the poor" — Jesus identifies kindness to the poor as the criterion of eschatological judgment: "Whatever you did for one of the least of these brothers and sisters of mine, you did for me" (Matt 25:40). The blessedness promised here (<em>ʾašrêw</em>) is the same beatitude-language that Jesus deploys in the Sermon on the Mount for the poor themselves (Matt 5:3). Christ himself is simultaneously the poor one who receives kindness and the Lord who rewards those who showed it.</p>',
    "22": '<p><em>Theme.</em> "Those who plan good find loyal love and faithfulness" (<em>ḥesed wəʾĕmet</em>) — the covenantal pair <em>hesed</em> and <em>ʾĕmet</em> (loving-kindness and faithfulness) that characterizes God\'s relationship with Israel is what those who plan good receive. Christ is the one in whom these covenant attributes are finally embodied: "grace and truth" (<em>charis kai alētheia</em>, John 1:14) are the NT parallel. Those who are "in Christ" — the one whose whole plan was the good of human redemption — receive the full covenantal blessing that this verse promises to those who plan good.</p>',
    "23": '<p><em>Theme.</em> "There is profit in all hard work" — Christ\'s redemptive work is the supreme instance of the hard-labor principle. The author of Hebrews describes the cross as an act of purposeful endurance: "for the joy set before him he endured the cross" (Heb 12:2) — profit through costly labor. The kingdom he wins through his suffering is the harvest of his hard work. "The Lord of the harvest" (Matt 9:38) first goes through the harvest\'s labor himself before sending workers; all kingdom productivity flows from his prior costly engagement.</p>',
    "24": '<p><em>Theme.</em> "The wealth of the wise is their crown" — Paul identifies Christ as the wisdom (<em>sophia</em>) of God (1 Cor 1:24, 30) and those in Christ as "heirs of God and co-heirs with Christ" (Rom 8:17), sharing his inheritance. The crown that wisdom generates — the royal dignity of the truly wise — is Christ\'s to give to those who share his wisdom through union with him. James promises "the crown of life" to those who love God (Jas 1:12); Peter promises "the crown of glory that will never fade" (1 Pet 5:4) — crowns distributed by the chief Shepherd who himself wears the diadem of glory.</p>',
    "25": '<p><em>Type.</em> "A truthful witness saves lives, but a false witness deals in lies" — the stakes of honest testimony reach their highest point in Christ\'s testimony on trial. He is the truthful witness who saves lives even at the cost of his own: his honest confession that he is "the Son of God" (Matt 26:63–64) before the Sanhedrin secures his condemnation but saves those who will believe his testimony. The false witnesses who testify against him (Matt 26:60–61) embody the deadly damage that false witness does — but their lies cannot undo the life-saving power of his truth.</p>',
    "26": '<p><em>Theme.</em> "The fear of the LORD is a source of strong confidence, and his children will find refuge in him" — Christ as the one in whom God\'s children find their refuge. Paul identifies believers as those who have received "the Spirit of adoption to sonship. And by him we cry, \'Abba, Father\'" (Rom 8:15) — the filial access to divine refuge that this verse promises. Christ is simultaneously the strong confidence (he in whom we trust) and the model of confidence (his Gethsemane prayer is the supreme example of fearful-reverent trust in the Father).</p>',
    "27": '<p><em>Allusion.</em> "The fear of the LORD is a fountain of life, turning one away from the traps of death" — identical in substance to 13:14 ("the teaching of the wise is a fountain of life"), confirming that fear-of-YHWH and wisdom are interchangeable. Christ, who is identified as the fountain of living water (John 4:14; 7:38), is the source from which this fountain flows. The traps of death (<em>moqəšê māwet</em>) that wisdom turns one away from are the same bondages from which Christ releases: "the fear of death" that keeps people in "slavery all their lives" (Heb 2:15).</p>',
    "28": '<p><em>Type.</em> "A large population is a king\'s glory" — Christ, the divine King, is glorified in the vastness of his people. "A great multitude that no one could count, from every nation, tribe, people and language, standing before the throne" (Rev 7:9) is the fulfillment of the royal glory that this proverb describes. The "ruined prince" of the second half points toward every alternative sovereignty — political, religious, ideological — whose decline in adherents signals its failure. Christ\'s glory increases as his people multiply across history.</p>',
    "29": '<p><em>Revelation of God.</em> "Whoever is slow to anger shows great understanding" — Christ as the supreme embodiment of patience. Peter describes God\'s delay in judgment as patience: "He is patient with you, not wanting anyone to perish" (2 Pet 3:9). Christ demonstrates this patience toward his disciples\' repeated failures (Matt 26:40–45) and toward the hostile crowds whose questioning he endures. His "great understanding" is the divine comprehension of human weakness — "for he knows how we are formed, he remembers that we are dust" (Ps 103:14) — that grounds patience rather than quick anger.</p>',
    "30": '<p><em>Theme.</em> "A calm and contented heart brings health to the body, but envy eats away at the bones" — the peace Christ offers (John 14:27, "my peace I give to you, not as the world gives") is the foundation of the calm heart that produces health. Paul\'s "peace of God, which transcends all understanding" that "will guard your hearts and minds" (Phil 4:7) is the body-health that this proverb locates in inner peace. Envy as the destroyer corresponds to the "strife and selfish ambition" that Paul contrasts with love — the disintegrating passion that Christ\'s peace displaces.</p>',
    "31": '<p><em>Direct.</em> "Whoever shows kindness to the needy honors him" — Christ identifies himself directly with the needy: "I was hungry and you gave me food, I was thirsty and you gave me drink" (Matt 25:35). To show kindness to the needy is to honor God because God is present in the needy in a way that this proverb anticipates. Christ\'s identification with "the least of these" (Matt 25:40) makes the Maker\'s presence in the poor literally visible in the incarnate Son who becomes poor (2 Cor 8:9) to stand beside those who have nothing.</p>',
    "32": '<p><em>Type.</em> "The righteous have hope even in death" — the resurrection of Christ is the supreme fulfillment of this verse. His hope in death was vindicated on the third day; his resurrection is the first installment of the "righteous have hope even in death" promise extended to all who are in him. Paul grounds resurrection hope in Christ\'s: "For since we believe that Jesus died and rose again, even so, through Jesus, God will bring with him those who have fallen asleep" (1 Thess 4:14). The righteous person\'s hope in death is not wishful thinking but a consequence of union with the one who proved that death is not the end.</p>',
    "33": '<p><em>Theme.</em> "Wisdom quietly rests in the heart of the discerning" — Paul describes wisdom\'s indwelling in terms of Christ\'s presence: "Christ in you, the hope of glory" (Col 1:27). The "wisdom and knowledge" hidden in Christ (Col 2:3) is the fulfillment of the wise person\'s quiet wisdom-rest. Wisdom no longer merely resides in the discerning heart as a quality cultivated through formation; it dwells there as the person of Christ through the Spirit — a personalized, relational presence of the wisdom who is also a person.</p>',
    "34": '<p><em>Theme.</em> "Righteousness lifts a nation up, but sin brings disgrace to any people" — Christ as the source of national righteousness. The OT vision of a righteous nation is fulfilled in the church as a "holy nation" (1 Pet 2:9), and ultimately in the eschatological kingdom where "the nation of the saved" walks by the light of the Lamb (Rev 21:24). Christ\'s righteousness imputed to his people is the only basis for the corporate righteousness that lifts a community beyond shame. The nations\'s sin-disgrace is overcome only by participation in the Righteous One.</p>',
    "35": '<p><em>Type.</em> "A king\'s favor rests on a servant who acts wisely" — Isaiah\'s Servant who "acted wisely" (<em>yaskîl</em>, Isa 52:13, the same word as <em>śekel</em> in this verse) and therefore receives the favor/exaltation of the King is the direct fulfillment of this proverb\'s pattern. Christ as the Servant of the LORD who "acted wisely" in his obedient redemptive mission receives the highest royal favor: "Therefore God exalted him to the highest place and gave him the name that is above every name" (Phil 2:9). The king\'s favor on the wise servant is the type; Christ\'s exaltation is the antitype.</p>'
  },
  "15": {
    "1": '<p><em>Revelation of God.</em> "A gentle answer turns away anger" — Christ embodies the gentle answer (<em>maʿăneh rak</em>) that disarms hostility. In his interactions with adversaries — the woman caught in adultery (John 8:1–11), the Samaritan woman (John 4), even the high priest\'s servant whose ear he restores (Luke 22:51) — he responds with calibrated gentleness. "I am gentle and humble in heart" (Matt 11:29) is his self-description; the turning away of anger through gentleness is not a tactical choice but the expression of his character as the one in whom divine love takes flesh.</p>',
    "2": '<p><em>Revelation of God.</em> "The tongue of the wise presents knowledge rightly" — Christ\'s teaching is the supreme instance of knowledge rightly presented. He "taught as one who had authority" (Matt 7:29) — not just accurately but with the intrinsic authority of the one who is the source of the knowledge he communicates. The crowds who heard the Sermon on the Mount and "were amazed at his teaching" (Matt 7:28) experienced the qualitative difference between wisdom correctly presented by the source and wisdom secondhand. He does not relay wisdom; he speaks from within it.</p>',
    "3": '<p><em>Revelation of God.</em> "The LORD\'s eyes are everywhere, watching both the evil and the good" — Christ, who "knew what was in each person" (John 2:25) and who is described as having "eyes like blazing fire" (Rev 1:14; 2:18) in the letters to the seven churches, embodies the divine omniscience that this verse describes. His specific knowledge of the individual — Nathanael under the fig tree (John 1:48), the woman\'s five husbands (John 4:18), Zacchaeus in the tree (Luke 19:5) — confirms that the divine watching is not passive surveillance but active, relational knowing.</p>',
    "4": '<p><em>Type.</em> "A wholesome tongue is a tree of life" — the tongue that gives life is a type of Christ who IS the tree of life (Rev 2:7; 22:2, 14). His words are not merely wholesome but life-constituting: "The words I have spoken to you are spirit and they are life" (John 6:63). The twisted tongue that crushes the spirit corresponds to the "old serpent" whose speech in Eden was the original life-crushing deception. The contrast between the life-giving tongue and the spirit-crushing tongue is the contrast between Christ\'s speech and the adversary\'s.</p>',
    "5": '<p><em>Theme.</em> Christ demonstrates in his own person the "good sense" of accepting correction. He "learned obedience from what he suffered" (Heb 5:8) — the discipline of submission to the Father\'s will, even unto death. Where the fool rejects the Father\'s discipline (as Israel repeatedly did), Christ the obedient Son receives it fully. This does not imply that Christ had failings to be corrected, but that his formation through suffering was the path of wisdom-through-discipline that this verse commends: accepting correction rather than rejecting it as a threat.</p>',
    "6": '<p><em>Theme.</em> "The household of the righteous holds great treasure" — the great treasure of the righteous household is Christ himself, who is "wisdom from God, and righteousness and sanctification and redemption" (1 Cor 1:30) and in whom "are hidden all the treasures of wisdom and knowledge" (Col 2:3). The household he builds (Matt 16:18) holds the greatest possible treasure: the people of God who are his inheritance (Eph 1:18) and in whom he dwells (Col 1:27). The wicked\'s trouble corresponds to the poverty of any life oriented around lesser goods.</p>',
    "7": '<p><em>Theme.</em> "The lips of the wise spread knowledge" — Christ\'s evangelistic commission extends the wisdom tradition\'s knowledge-spreading to the ends of the earth. "Go and make disciples of all nations" (Matt 28:19) is the supreme sending of wise lips to spread the knowledge of God. The disciples\' preaching is itself an extension of Christ\'s wisdom-spreading lips (Acts 1:1 — what Jesus "began to do and to teach" continues through the apostolic community). The Spirit\'s work of bringing to remembrance "everything I have said to you" (John 14:26) sustains the spreading.</p>',
    "8": '<p><em>Type.</em> "The LORD detests the sacrifice of the wicked, but the prayer of the upright is his delight" — the sacrificial distinction that this verse articulates is resolved in Christ. His sacrifice is the one acceptable offering that the sacrifices of the wicked could never be: "By one sacrifice he has made perfect forever those who are being made holy" (Heb 10:14). The detested sacrifices of the old system — when offered by the wicked or as a substitute for obedience (Isa 1:11–15) — are replaced by Christ\'s self-offering. Simultaneously, his intercession as the upright one is the prayer that the Father eternally delights in.</p>',
    "9": '<p><em>Revelation of God.</em> "He loves whoever earnestly pursues righteousness" — Christ is both the object of the Father\'s love ("This is my Son, whom I love, in whom I am well pleased," Matt 3:17) and the one through whom earnest pursuit of righteousness becomes possible. Paul\'s declaration that "God made him who had no sin to be sin for us, so that in him we might become the righteousness of God" (2 Cor 5:21) makes Christ the path by which those who did not pursue righteousness can now pursue it authentically, receiving both the love this verse promises and the righteousness it rewards.</p>',
    "10": '<p><em>Theme.</em> "There is harsh discipline for the one who leaves the right path, and whoever hates correction will die" — Christ received the harsh discipline that belongs to those who left the right path, though he never left it. Isaiah\'s servant is described as "stricken by God, smitten by him, and afflicted" (Isa 53:4) — bearing the discipline that belongs to the straying. Those who "hate correction" and refuse to return to the path correspond to the final condition of those who reject the gospel. Christ\'s bearing of the harsh discipline opens the possibility of return for all who will accept correction.</p>',
    "11": '<p><em>Revelation of God.</em> "Death and Destruction lie open before the LORD — how much more the hearts of people!" — Christ descended into the regions of death (Acts 2:27, 31; Eph 4:9–10; 1 Pet 3:19) and emerged as the conquering Lord. The divine omniscience that penetrates even Sheol and Abaddon is embodied in Christ who holds "the keys of death and Hades" (Rev 1:18). His descent into the depths proves that nothing — not even the depths of human corruption or the dimensions of death — lies beyond the LORD\'s penetrating sight and sovereign reach.</p>',
    "12": '<p><em>Theme.</em> "A mocker does not like being corrected and will not seek the company of the wise" — the mockers who surrounded the cross (Matt 27:39–44) are the supreme instance: given the presence of wisdom incarnate, they respond with scorn rather than reception. "He came to his own, but his own people did not receive him" (John 1:11) describes the tragically closed community of the mockers. Contrast with those who "seek the company of the wise" — the disciples who drew near to learn, the crowds who pressed to hear — and whose openness was itself the condition of their formation.</p>',
    "13": '<p><em>Revelation of God.</em> "A joyful heart makes a bright face, but a crushed spirit shows in the countenance" — Christ who is "familiar with suffering" and whose face was "marred beyond human likeness" (Isa 52:14) in his passion is also the one who promises that his own joy will be in his disciples and "that your joy may be complete" (John 15:11). His countenance, described as shining "like the sun" at the transfiguration (Matt 17:2) and as the source of the new Jerusalem\'s light (Rev 22:5), is the ultimate bright face of the joy-filled heart — a face that bears the marks of suffering transformed into glory.</p>',
    "14": '<p><em>Theme.</em> "A discerning heart is always seeking knowledge" — Christ models the seeking heart that is the disposition of discipleship. "Follow me" (Mark 1:17) is an invitation to the ongoing, active seeking of knowledge that this verse commends. Paul prays that believers would have "the spirit of wisdom and revelation" for "the knowledge of him" (Eph 1:17), recognizing that union with Christ does not end seeking but deepens it. The discerning heart that always seeks knowledge is the heart that never exhausts the inexhaustible depths of Christ (cf. Eph 3:18–19).</p>',
    "15": '<p><em>Theme.</em> "A joyful heart provides a constant feast" — Paul\'s instruction to "Rejoice always" (1 Thess 5:16; Phil 4:4) and the promise of "the peace of God, which transcends all understanding" (Phil 4:7) constitute the NT version of this proverb\'s inner feast. Christ himself is the source of this joy: "These things I have spoken to you, that my joy may be in you, and that your joy may be full" (John 15:11). The joyful heart\'s feast is the feast of union with Christ — the one who turns water into wine (John 2) and who himself is the food and drink that provides inexhaustible nourishment.</p>',
    "16": '<p><em>Revelation of God.</em> "Better to have little with the fear of the LORD than great wealth with turmoil" — Christ\'s beatitude "Blessed are the poor in spirit, for theirs is the kingdom of heaven" (Matt 5:3) and his own life of poverty ("Foxes have dens and birds have nests, but the Son of Man has no place to lay his head," Luke 9:58) embody the better-ness of little-with-God. He is the ultimate demonstration of this proverb: he who had all things (John 17:5) chose poverty and the fear of the Father over the "turmoil" of worldly wealth that the enemy offered (Matt 4:8–9).</p>',
    "17": '<p><em>Theme.</em> "Better a simple meal where love is present than a lavish feast accompanied by hatred" — Christ\'s fellowship meals consistently subvert the prestige-economics of ancient banqueting. His table fellowship with tax collectors and sinners (Matt 9:10–13), the feeding of the multitudes with bread and fish (not a lavish feast), and the Last Supper with bread and wine (simple fare, supreme love) all exemplify the simple-meal-with-love principle. The new covenant\'s Eucharistic meal is the perpetual enactment of this proverb: simple elements, maximum love.</p>',
    "18": '<p><em>Theme.</em> "Whoever is slow to anger quiets it" — Christ as the peacemaker who quiets strife through his own patience. "Blessed are the peacemakers, for they will be called children of God" (Matt 5:9) — Christ is the Son of God who is the supreme peacemaker, making peace "through his blood, shed on the cross" (Col 1:20). His slowness to anger in the face of maximum provocation (the Passion narrative) is the most powerful possible quieting of strife — it absorbs the violence rather than escalating it.</p>',
    "19": '<p><em>Theme.</em> "The road of the upright is a level highway" — Isaiah applies the level-highway image to the messianic age: "Prepare the way for the LORD; make straight in the wilderness a highway for our God. Every valley shall be raised up, every mountain and hill made low" (Isa 40:3–4, cited in Matt 3:3 of John the Baptist preparing for Christ). Christ is both the one for whom the highway is prepared and the one who himself is "the Way" — the level path that Israel could not walk on its own. John 14:6 is the fulfilment of the level highway Isaiah promised.</p>',
    "20": '<p><em>Revelation of God.</em> "A wise son brings his father joy" — Christ is the Son who brings the Father perfect joy: "This is my Son, whom I love; with him I am well pleased" (Matt 3:17; 17:5). The entire gospel narrative moves toward this divine delight — the Father\'s joy in the Son who does everything the Father gives him to do (John 5:19–20; 17:4). Christ fulfills this proverb not as one instance of the wise-son pattern but as its ultimate realization: the Son whose wisdom is perfect brings the Father\'s joy to its highest expression.</p>',
    "21": '<p><em>Theme.</em> "A person of understanding walks straight" — Christ is the one who walks perfectly straight, the <em>euthys</em> (immediately, directly, straight) of Mark\'s Gospel expressing his direct, purposeful movement. He sets his face toward Jerusalem (Luke 9:51) — the supreme act of walking straight toward the destination that his mission requires, despite the disciples\' resistance and his own human recoiling. His straight walk is the model for the disciple\'s walk — not meandering but purposeful, oriented by the understanding of where the journey leads.</p>',
    "22": '<p><em>Theme.</em> "With many counselors they succeed" — Christ gathers around himself the community of discernment. He sends the disciples out in pairs (Mark 6:7; Luke 10:1) — built-in counsel. He promises the Spirit as counselor (<em>Paraklete</em>, "one called alongside," John 14:16) who guides into all truth. The wisdom he builds into his community is not the wisdom of one brilliant individual but the distributed wisdom of the body, where "the body does not consist of one part but of many" (1 Cor 12:14). The many-counselor principle is the shape of the Spirit-led community.</p>',
    "23": '<p><em>Theme.</em> "A person finds joy in giving the right answer, and how good is a timely word!" — Christ gives the right answer at every moment of his earthly ministry. His answers to the Pharisees\' trick questions (Matt 22:15–40) are celebrated precisely as "the right answer" — leaving his opponents with nothing to say. His promise that the Spirit will "give you words and wisdom that none of your adversaries will be able to resist" (Luke 21:15) extends his own timely-word capacity to his disciples. The joy in giving the right answer is the joy of saying what is needed when it is needed.</p>',
    "24": '<p><em>Theme.</em> "The way of life leads upward for the wise, so that they may avoid Sheol below" — Christ\'s ascension is the supreme "way upward" — he who descended to the lowest depths (Eph 4:9) rose to the highest heights (Eph 4:10) and now leads the wise upward by his Spirit. The avoidance of Sheol through wisdom finds its fullest expression in the promise that those who believe will not see death (John 8:51; 11:25–26) but will be raised to life. Christ is the wisdom that leads the upward way: "If anyone is in Christ, the new creation has come: The old has gone, the new is here!" (2 Cor 5:17).</p>',
    "25": '<p><em>Revelation of God.</em> "The LORD will pull down the house of the proud, but he maintains the widow\'s property lines" — Christ demonstrates this in his temple action (pulling down the house of pride-turned-commerce, Matt 21:12–13) and in his specific care for widows (Luke 7:11–17, raising the widow of Nain\'s son; Luke 21:1–4, commending the widow\'s offering). The God who maintains the widow\'s boundary-line is the God who appears in Christ defending the structurally vulnerable — the widow, the poor, the socially marginal — against those who exploit their vulnerability.</p>',
    "26": '<p><em>Revelation of God.</em> "The LORD detests the plans of the wicked, but pure words are pleasing to him" — Christ\'s speech is supremely "pure words" (<em>ʾimrê ṭāhōr</em>) — speech without admixture of deception, self-interest, or malice. Peter\'s citation of Isaiah 53:9 ("No deceit was found in his mouth," 1 Pet 2:22) identifies Christ as the living instance of the pure-words principle. His speech pleases the Father (Matt 3:17; 17:5 — the Father speaks his pleasure at the Son\'s words and works). Every word Christ speaks is the divine pleasure given verbal form.</p>',
    "27": '<p><em>Allusion.</em> "Whoever refuses bribes will live" — Christ refuses the ultimate bribe: the enemy offers him "all the kingdoms of the world and their splendor" (Matt 4:8–9) in exchange for worship. His refusal ("Away from me, Satan! For it is written: \'Worship the Lord your God, and serve him only,\'" Matt 4:10) is the supreme instance of the bribe-refusal that this verse connects to life. The one who could have taken the kingdoms on easy terms takes them instead through the cross — refusing the corrupt acquisition that would have brought his household trouble.</p>',
    "28": '<p><em>Revelation of God.</em> "The heart of the righteous weighs its answer carefully" — Christ\'s deliberate, measured speech is one of the most consistent features of the Gospel portraits. He often pauses before answering (John 8:6–8, writing in the sand before responding to the woman caught in adultery). He asks clarifying questions (Mark 10:3, 51; Luke 8:30). He sometimes gives no answer at all (Mark 14:61; 15:5). His weighing of answers carefully is the embodiment of the righteous heart that does not blurt but considers. His speech is always appropriate to the moment — a form of wisdom in action.</p>',
    "29": '<p><em>Theme.</em> "He hears the prayer of the righteous" — Christ as our high priest intercedes for the righteous: "He always lives to intercede for them" (Heb 7:25). The LORD\'s hearing of the righteous is mediated through Christ\'s ongoing priestly presence "at the right hand of God" (Rom 8:34). His own prayer for his disciples (John 17) is the supreme righteous prayer that the Father hears; the disciples\' prayers "in my name" (John 14:13–14) are heard because they are incorporated into his priestly intercession. Distance from the wicked / nearness to the righteous is the pattern of the mediating Christ.</p>',
    "30": '<p><em>Theme.</em> "Good news refreshes the whole body" — the gospel (<em>euangelion</em>, good news) is the ultimate refreshment of the body. Isaiah 52:7 ("How beautiful are the feet of those who bring good news!") grounds the NT proclamation of the gospel in this wisdom-tradition recognition that good news has a physically restorative quality. The resurrection of Christ is the best news conceivable — death overcome, life restored, the enemy defeated — and its reception refreshes not only spirits but (in eschatological promise) bodies themselves, as resurrection-hope is the promise of bodily renewal (Phil 3:21; 1 Cor 15:42–44).</p>',
    "31": '<p><em>Theme.</em> "The ear that heeds life-giving correction will find its home among the wise" — the disciples who heeded Christ\'s often-corrective teaching found their home in the community of the wise — the household of God. He who "will build my church" (Matt 16:18) is simultaneously the correction-giver whose life-giving rebukes (Peter\'s denial predicted; Thomas\'s doubt challenged; the disciples\' ambition redirected) form the community that becomes "no longer foreigners and strangers, but fellow citizens with God\'s people and members of his household" (Eph 2:19).</p>',
    "32": '<p><em>Theme.</em> "Whoever accepts reproof gains insight" — the disciples who accepted Christ\'s correction were formed by it into wisdom. Paul\'s account of the Christian life as continuous correction by Scripture, useful "for reproof, for correction, and for training in righteousness" (2 Tim 3:16), extends the formation-through-accepted-reproof principle to the whole community of the redeemed. Christ does not merely teach insight but gives it through the Spirit (John 16:13), who "will convince the world concerning sin and righteousness and judgment" (John 16:8) — a kind of cosmic reproof that leads to insight for those who accept it.</p>',
    "33": '<p><em>Direct.</em> "The fear of the LORD is training in wisdom, and humility comes before honor" — Paul applies the second clause directly to Christ: "he humbled himself by becoming obedient to death — even death on a cross! Therefore God exalted him to the highest place" (Phil 2:8–9). The humility-before-honor sequence is Christ\'s own path — the deepest humiliation in human history followed by the highest exaltation. His exaltation does not contradict his humility but is its consequence: because he did not grasp at equality with God (Phil 2:6), God gave it to him in the form no one could take away. This is the wisdom that the fear of the LORD produces when taken to its ultimate depth.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'proverbs')
    merge_comm(existing, PROVERBS)
    save_comm('mkt-christ', 'proverbs', existing)
    print('Proverbs 13–15 mkt-christ written.')

if __name__ == '__main__':
    main()
